// Navbar.js
import React from "react";
import { useNavigate, Link } from "react-router-dom";

export default function Navbar() {
  const navigate = useNavigate();

  const handleNavScroll = (hash) => {
    navigate(`/#${hash}`);
  };

  return (
    <nav className="sticky top-0 bg-navy shadow-md z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
        <div className="flex items-center space-x-3">
          <img src="/alforis_logo_precise_round.png" alt="Logo Alforis" className="h-10 w-10 rounded-full" />
          <span className="text-white font-title text-xl font-semibold">Alforis</span>
        </div>
        <div className="hidden md:flex space-x-8 text-sm font-medium">
          <button onClick={() => handleNavScroll("accueil")} className="text-white hover:text-gold transition">Accueil</button>
          <button onClick={() => handleNavScroll("services")} className="text-white hover:text-gold transition">Services</button>
          <button onClick={() => handleNavScroll("equipe")} className="text-white hover:text-gold transition">Équipe</button>
          <button onClick={() => handleNavScroll("contact")} className="text-white hover:text-gold transition">Contact</button>
        </div>
        <Link
          to="/rendezvous"
          className="bg-gold text-navy px-4 py-2 rounded-md text-sm font-semibold hover:opacity-90 transition"
        >
          Prendre un RDV
        </Link>
      </div>
    </nav>
  );
}
